const label_222: ByteArray = #"000de140"
const label_100: ByteArray = #"000643b0"

fn has_cip68_label(name: ByteArray, label: ByteArray) -> Bool {
  bytearray.length(name) >= 4 && bytearray.take(name, 4) == label
}

fn is_cip68_token(name: ByteArray) -> Bool {
  has_cip68_label(name, label_222) || has_cip68_label(name, label_100)
}

/// No CIP-68 labeled token may have |qty| > 1 (no fungible copies)
fn no_cip68_fungible(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  list.all(
    dict.to_pairs(tokens),
    fn(p) {
      let Pair(name, qty) = p
      if is_cip68_token(name) {
        qty == 1 || qty == -1
      } else {
        True
      }
    },
  )
}

validator cip68_no_fungible {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    // Must mint or burn at least one token under this policy
    let token_pairs = dict.to_pairs(tokens)
    let is_non_empty = !list.is_empty(token_pairs)
    // Every token name under this policy must carry a valid CIP-68 label
    let all_cip68_labeled =
      list.all(
        token_pairs,
        fn(p) {
          let Pair(name, _qty) = p
          is_cip68_token(name)
        },
      )
    // No CIP-68 token in this mint may have a quantity other than 1 or -1
    let quantity_ok = no_cip68_fungible(tokens)
    is_non_empty && all_cip68_labeled && quantity_ok
  }
}

